parameters.jsCode:
// Filter job openings for leadership roles
const leadershipPattern = /\b(CRO|CMO|CTO|VP|Vice President|Head of|Chief)\b/i;

const items = $input.all();
const results = [];

for (const item of items) {
  const jobOpenings = item.json.data || [];
 const domain = $('Split Into Batches').first().json.domain || '';
const companyName = $('Split Into Batches').first().json.company_name || '';

  const leadershipRoles = jobOpenings.filter(job => {
    const title = (job.attributes?.title || job.title || '').toString();
    return leadershipPattern.test(title);
  });

  if (leadershipRoles.length > 0) {
    results.push({
      json: {
        domain: domain,
        company_name: companyName,
        leadership_roles: leadershipRoles.map(job => ({
          title: job.attributes?.title || job.title || 'Unknown',
          location: job.attributes?.location || job.location || 'Not specified',
          url: job.attributes?.url || job.url || ''
        })),
        leadership_found: true
      }
    });
  } else {
    results.push({
      json: {
        domain: domain,
        company_name: companyName,
        leadership_roles: [],
        leadership_found: false
      }
    });
  }
}

return results;

const salesPattern = /\b(SDR|Sales|Account Executive|Business Development)\b/i;

const items = $input.all();
const results = [];

for (const item of items) {
  const jobs = item.json.data || [];

  const domain = $('Split Into Batches').first().json.domain || '';
  const companyName = $('Split Into Batches').first().json.company_name || '';

  const salesRoles = jobs.filter(job => {
    const title = (job.attributes?.title || '').toString();
    return salesPattern.test(title);
  });

  results.push({
    json: {
      domain,
      company_name: companyName,
      sales_roles: salesRoles.map(j => j.attributes?.title),
      sales_hiring: salesRoles.length > 0
    }
  });
}

return results;

