// Build a personalized AI prompt with company + role context
const items = $input.all();
const results = [];

for (const item of items) {
  const companyData = item.json.data?.attributes || item.json.data || {};
  const domain = item.json.domain || $('Filter Leadership Roles').first().json.domain || '';
  const companyName = companyData.name || $('Filter Leadership Roles').first().json.company_name || domain;
  const industry = companyData.industry || 'technology';
  const employeeCount = companyData.employee_count || 'unknown';
  const description = companyData.description || '';
  const location = companyData.location || 'unknown location';

  const leadershipRoles = $('Filter Leadership Roles').first().json.leadership_roles || [];
  const rolesList = leadershipRoles.map(r => r.title).join(', ');

  // dynamic signal context
  let signalContext = "";

  if (leadershipRoles.length > 0) {
    signalContext = `They are hiring for leadership roles: ${rolesList}`;
  } else if ($('Retrieve Company Job Openings').first().json.data.length >= 10) {
    signalContext = `They are rapidly scaling with multiple open roles (${$('Retrieve Company Job Openings').first().json.data.length} openings).`;
  } else {
    signalContext = `They are actively hiring across different teams.`;
  }

  const prompt = `You are a B2B sales development representative writing a personalized cold outreach email.

Context about the target company:
- Company: ${companyName}
- Domain: ${domain}
- Industry: ${industry}
- Employee count: ${employeeCount}
- Location: ${location}
- Description: ${description}

${signalContext}

Write a concise, personalized outreach email (max 150 words) that:
1. References the hiring signal
2. Connects how our solution could help
3. Offers a brief call to discuss
4. Has a compelling subject line

Format your response as:
Subject: [subject line]

[email body]

Keep the tone professional but conversational. Do not use generic filler phrases.`;

  results.push({
    json: {
      domain: domain,
      company_name: companyName,
      leadership_roles: leadershipRoles,
      roles_list: rolesList,
      ai_prompt: prompt,
      recipient_email: `outreach@${domain}`
    }
  });
}

return results;

